const{MongoClient:MongoClient}=require("mongodb"),MONGO_URI=process.env.MONGO_URI;let client;async function getDb(){return client||(client=await MongoClient.connect(MONGO_URI)),client.db("eltri")}module.exports=async function(e,n){if(n.setHeader("Access-Control-Allow-Origin","*"),n.setHeader("Access-Control-Allow-Methods","GET"),"OPTIONS"===e.method)return n.status(200).end();if(e.headers["x-admin-token"]!==process.env.ADMIN_TOKEN)return n.status(401).json({error:"Unauthorized"});const t=await getDb(),o=await t.collection("views").find().toArray(),r={};return o.forEach(e=>r[e.id]=e.views),n.json(r)};